mapper.select:
SELECT A.*, B.name, B.id, B.sex, B.cellphone_A, B.cellphone_B, B.id_file, B.passport_file, B.name_index, B.chairman, B.order_pk, B.lock_flg, B.delete_flg, B.id_type, B.as_adult, C.departure_date, C.product_name, C.product_model, C.days, C.product_pk, C.product_manager_number FROM product_order_name A LEFT JOIN sale_order_name_list B ON A.name_pk = B.pk LEFT join product_order C ON A.product_order_number = C.order_number
and C.product_name like concat('%', #{params.bo.product_name,jdbcType=VARCHAR},'%')
and C.product_model like concat('%', #{params.bo.product_model,jdbcType=VARCHAR},'%')
and A.product_order_number like concat('%',#{params.bo.product_order_number,jdbcType=VARCHAR},'%')
and A.team_number like concat('%',#{params.bo.team_number,jdbcType=VARCHAR},'%')
and B.name like concat('%',#{params.bo.name,jdbcType=VARCHAR},'%')
and C.departure_date >=#{params.bo.date_from,jdbcType=VARCHAR}
and C.departure_date <=#{params.bo.date_to,jdbcType=VARCHAR}
and A.operate_status in
#{params.bo.operate_statuses[${index}]}
and C.product_manager_number IN
#{params.bo.product_manager_numbers[${index}]}
ORDER BY A.product_order_number,A.team_number
